Extensions.ExtractScript:
param([xml] $Document)
$base = 'C:\Windows\Setup\Scripts'
if (-not (Test-Path $base)) { New-Item $base -ItemType Directory -Force | Out-Null }
foreach ($file in $Document.unattend.Extensions.File) {
    $path = [System.Environment]::ExpandEnvironmentVariables($file.GetAttribute('path'))
    try {
        $bytes = [System.Text.Encoding]::UTF8.GetPreamble() + [System.Text.Encoding]::UTF8.GetBytes($file.InnerText.Trim())
        [System.IO.File]::WriteAllBytes($path, $bytes)
    } catch { continue }
}

Extensions.File:
$ErrorActionPreference = 'Stop'
$outputFile = 'C:\Windows\Setup\Scripts\ComputerName.txt'
if (-not (Test-Path (Split-Path $outputFile))) { New-Item (Split-Path $outputFile) -ItemType Directory -Force | Out-Null }
try {
    $cpu = Get-CimInstance Win32_Processor -Property Manufacturer -ErrorAction Stop | Select-Object -First 1
    $mfr = $cpu.Manufacturer.Trim()
} catch {
    $mfr = (Get-ItemProperty 'HKLM:\HARDWARE\DESCRIPTION\System\CentralProcessor\0' -Name 'ProcessorNameString' -EA SilentlyContinue).'ProcessorNameString'
    if ($mfr -match 'AMD') { $mfr = 'AMD' } elseif ($mfr -match 'Intel') { $mfr = 'Intel' } else { $mfr = 'Unknown' }
}
$cpuLetter = switch -Regex ($mfr) {
    'Intel' { @('N','P','C') | Get-Random }
    'AMD'   { @('A','M','D') | Get-Random }
    default { 'V' }
}
$num1  = Get-Random -Minimum 55 -Maximum 100
$char2 = [char](78 + (Get-Random -Maximum 13))
$num2  = Get-Random -Minimum 100 -Maximum 999
$newName = "DEVICE-$cpuLetter$num1$char2$num2"
if ($newName.Length -gt 15) { $newName = $newName.Substring(0, 15) }
$newName | Out-File -LiteralPath $outputFile -Encoding utf8 -Force

$ErrorActionPreference = 'Stop'
$nameFile = 'C:\Windows\Setup\Scripts\ComputerName.txt'
if (-not (Test-Path $nameFile)) { exit 1 }
$newName = (Get-Content $nameFile).Trim()
try {
    Rename-Computer -NewName $newName -Force -ErrorAction Stop
} catch {
    $paths = @(
        'HKLM:\SYSTEM\CurrentControlSet\Control\ComputerName\ComputerName',
        'HKLM:\SYSTEM\CurrentControlSet\Control\ComputerName\ActiveComputerName',
        'HKLM:\SYSTEM\CurrentControlSet\Services\Tcpip\Parameters'
    )
    Set-ItemProperty -Path $paths[0] -Name 'ComputerName' -Value $newName -Type String -Force -EA SilentlyContinue
    Set-ItemProperty -Path $paths[1] -Name 'ComputerName' -Value $newName -Type String -Force -EA SilentlyContinue
    Set-ItemProperty -Path $paths[2] -Name 'Hostname' -Value $newName -Type String -Force -EA SilentlyContinue
    Set-ItemProperty -Path $paths[2] -Name 'NV Hostname' -Value $newName -Type String -Force -EA SilentlyContinue
}

$ErrorActionPreference = 'Continue'
$log = 'C:\Windows\Setup\Scripts\Specialize.log'
function Log($m) { "$(Get-Date -f 'yyyy-MM-dd HH:mm:ss') $m" | Add-Content $log -Force -EA SilentlyContinue }
Log "=== Specialize Start ==="
$os = Get-CimInstance Win32_OperatingSystem -EA SilentlyContinue
$isServer = $os.Caption -like '*Server*'
$isLTSC = $os.Caption -like '*LTSC*'
$build = [Environment]::OSVersion.Version.Build

function Set-RegSafe {
    param([string]$Path, [string]$Name, $Value, [string]$Type = 'DWord')
    try {
        if (-not (Test-Path $Path)) { New-Item -Path $Path -Force -EA SilentlyContinue | Out-Null }
        Set-ItemProperty -LiteralPath $Path -Name $Name -Value $Value -Type $Type -Force -EA Stop
        Log "Set: $Path\$Name = $Value"
    } catch {
        $regType = switch ($Type) { 'DWord'{'REG_DWORD'} 'String'{'REG_SZ'} default{'REG_DWORD'} }
        $val = if ($Type -eq 'String') { "`"$Value`"" } else { $Value }
        reg.exe add "`"$Path`"" /v "`"$Name`"" /t $regType /d $val /f 2>&1 | Out-Null
        Log "Fallback reg.exe: $Path\$Name"
    }
}

Set-RegSafe 'HKLM:\SYSTEM\Setup\MoSetup' 'AllowUpgradesWithUnsupportedTPMOrCPU' 1
Set-RegSafe 'HKLM:\SOFTWARE\Microsoft\Windows\CurrentVersion\Communications' 'ConfigureChatAutoInstall' 0
Set-RegSafe 'HKLM:\SOFTWARE\Policies\Microsoft\Windows\WindowsCopilot' 'TurnOffWindowsCopilot' 1
Set-RegSafe 'HKLM:\SOFTWARE\Policies\Microsoft\Windows\WindowsAI' 'DisableAIDataAnalysis' 1
Set-RegSafe 'HKLM:\SOFTWARE\Policies\Microsoft\Windows NT\DNSClient' 'EnableMulticast' 0
Set-RegSafe 'HKLM:\SYSTEM\CurrentControlSet\Control\FileSystem' 'LongPathsEnabled' 1
Set-RegSafe 'HKLM:\SYSTEM\CurrentControlSet\Control\Session Manager\Power' 'HiberbootEnabled' 0
Set-RegSafe 'HKLM:\SOFTWARE\Policies\Microsoft\Windows\CloudContent' 'DisableWindowsConsumerFeatures' 1
Set-RegSafe 'HKLM:\SOFTWARE\Policies\Microsoft\Windows\System' 'EnableActivityFeed' 0
Set-RegSafe 'HKLM:\SOFTWARE\Policies\Microsoft\Windows\System' 'PublishUserActivities' 0
Set-RegSafe 'HKLM:\SOFTWARE\Policies\Microsoft\Windows\DataCollection' 'AllowTelemetry' 0
Set-RegSafe 'HKLM:\SYSTEM\CurrentControlSet\Control\PriorityControl' 'Win32PrioritySeparation' 0x00000026
Set-RegSafe 'HKLM:\SOFTWARE\Microsoft\WindowsRuntime\ActivatableClassId\Windows.Gaming.GameBar.PresenceServer.Internal.PresenceWriter' 'ActivationType' 0
Set-RegSafe 'HKLM:\SOFTWARE\Microsoft\Windows\Windows Error Reporting' 'Disabled' 1
Set-RegSafe 'HKLM:\SOFTWARE\Microsoft\Windows\CurrentVersion\Explorer\FolderDescriptions\{31C0DD25-9439-4F12-BF41-7FF4EDA38722}\PropertyBag' 'ThisPCPolicy' 'Hide' 'String'
Set-RegSafe 'HKLM:\SOFTWARE\Policies\Microsoft\Windows\StorageSense' 'AllowStorageSenseGlobal' 0
Set-RegSafe 'HKLM:\SOFTWARE\Microsoft\Windows NT\CurrentVersion\Multimedia\SystemProfile' 'SystemResponsiveness' 0
Set-RegSafe 'HKLM:\SOFTWARE\Microsoft\Windows NT\CurrentVersion\Multimedia\SystemProfile' 'NetworkThrottlingIndex' 0xFFFFFFFF
Set-RegSafe 'HKLM:\SOFTWARE\Policies\Microsoft\Windows Defender\Spynet' 'SubmitSamplesConsent' 2
netsh.exe int tcp set global autotuning=normal 2>&1 | Out-Null

if (-not $isServer) {
    $pkgs = @('Microsoft.BingSearch*','Clipchamp.Clipchamp*','Microsoft.549981C3F5F10*','Microsoft.Windows.DevHome*','MicrosoftCorporationII.MicrosoftFamily*','Microsoft.WindowsFeedbackHub*','Microsoft.Getstarted*','Microsoft.MixedReality.Portal*','Microsoft.MicrosoftOfficeHub*','Microsoft.Office.OneNote*','Microsoft.OutlookForWindows*','Microsoft.MSPaint*','Microsoft.PowerAutomateDesktop*','MicrosoftCorporationII.QuickAssist*','Microsoft.SkypeApp*','Microsoft.MicrosoftSolitaireCollection*','MicrosoftTeams*','MSTeams*','Microsoft.Todos*','Microsoft.Wallet*','Microsoft.Xbox.TCUI*','Microsoft.XboxApp*','Microsoft.XboxGameOverlay*','Microsoft.XboxGamingOverlay*','Microsoft.XboxIdentityProvider*','Microsoft.XboxSpeechToTextOverlay*','Microsoft.GamingApp*','Microsoft.YourPhone*')
    if ($build -ge 22000 -and -not $isLTSC) { $pkgs += 'Microsoft.Windows.Ai.Copilot.Provider*' }
    foreach ($p in $pkgs) {
        try {
            $found = Get-AppxProvisionedPackage -Online | Where-Object { $_.DisplayName -like $p }
            if ($found) { Start-Sleep -Milliseconds 1500; $found | Remove-AppxProvisionedPackage -AllUsers -Online -EA SilentlyContinue | Out-Null; Log "Removed: $($found.DisplayName)" }
        } catch { Log "Skip pkg: $p" }
    }
    @('DevHomeUpdate','OutlookUpdate') | ForEach-Object { Remove-Item "HKLM:\Software\Microsoft\WindowsUpdate\Orchestrator\UScheduler_Oobe\$_" -Recurse -Force -EA SilentlyContinue }
}
Log "=== Specialize Complete ==="

$ErrorActionPreference = 'Continue'
$log = 'C:\Windows\Setup\Scripts\FirstLogon.log'
function Log($m) { "$(Get-Date -f 'yyyy-MM-dd HH:mm:ss') $m" | Add-Content $log -Force -EA SilentlyContinue }
Log "=== FirstLogon Start ==="
$os = Get-CimInstance Win32_OperatingSystem -EA SilentlyContinue
$isServer = $os.Caption -like '*Server*'
powercfg.exe /hibernate off 2>&1 | Out-Null
$hp = powercfg /l | Select-String 'High performance'
if ($hp) { powercfg.exe /setactive 8c5e7fda-e8bf-4a96-9a85-a6e23a8c635c 2>&1 | Out-Null }
powercfg.exe /change standby-timeout-ac 0 2>&1 | Out-Null
powercfg.exe /change standby-timeout-dc 0 2>&1 | Out-Null
powercfg.exe /change monitor-timeout-ac 0 2>&1 | Out-Null
function Test-IsSSD {
    $pd = Get-PhysicalDisk -EA SilentlyContinue | Where-Object { $_.BusType -ne 'USB' } | Sort-Object Size -Descending | Select-Object -First 1
    if ($pd.MediaType -eq 'SSD' -or $pd.BusType -eq 'NVMe') { return $true }
    $d = Get-CimInstance Win32_DiskDrive -Filter 'Index=0' -EA SilentlyContinue
    if ($d -and $d.Model -match 'NVMe|SSD|Samsung|WD|Crucial|Intel|SKHynix|Kingston|Micron') { return $true }
    return $false
}
if ((Test-IsSSD) -or $isServer) {
    try { Stop-Service SysMain -Force -EA SilentlyContinue; Set-Service SysMain -StartupType Disabled -EA SilentlyContinue } catch {}
}
$desktop = [Environment]::GetFolderPath('Desktop')
$src = 'C:\Windows\Setup\Scripts\DeploymentVerification.ps1'
$dest = Join-Path $desktop 'VerifyDeployment.lnk'
if (Test-Path $src) {
    try {
        $sh = New-Object -ComObject WScript.Shell
        $sc = $sh.CreateShortcut($dest)
        $sc.TargetPath = 'powershell.exe'
        $sc.Arguments = "-NoProfile -ExecutionPolicy Bypass -WindowStyle Hidden -File `"$src`""
        $sc.WorkingDirectory = 'C:\Windows\Setup\Scripts'
        $sc.Description = 'Checks deployment configuration status'
        $sc.IconLocation = 'shell32.dll,134'
        $sc.Save()
    } catch {}
}
Log "=== FirstLogon Complete ==="

#requires -RunAsAdministrator
$ErrorActionPreference = 'Continue'
$ProgressPreference = 'SilentlyContinue'
$os = Get-CimInstance Win32_OperatingSystem -ErrorAction SilentlyContinue
$report = [System.Collections.ArrayList]::new()
function Test-RegValue {
    param([string]$Path, [string]$Name, $Expected)
    try {
        if (Test-Path $Path) {
            $actual = (Get-ItemProperty -LiteralPath $Path -Name $Name -ErrorAction Stop).$Name
            if ($actual -eq $Expected) { return 'PASS' }
            return "FAIL (Actual: $actual)"
        }
        return 'MISSING'
    } catch { return 'ERROR' }
}
$report.Add("Configuration Verification Report | $(Get-Date -f 'yyyy-MM-dd HH:mm:ss')") | Out-Null
$report.Add("OS: $($os.Caption) | Build: $([Environment]::OSVersion.Version.Build) | User: $env:USERNAME") | Out-Null
$report.Add('') | Out-Null
$checks = @(
    @{ Cat='HKLM'; Check='Allow Upgrades on Unsupported Hardware'; Path='HKLM:\SYSTEM\Setup\MoSetup'; Name='AllowUpgradesWithUnsupportedTPMOrCPU'; Exp=1 },
    @{ Cat='HKLM'; Check='Disable Copilot'; Path='HKLM:\SOFTWARE\Policies\Microsoft\Windows\WindowsCopilot'; Name='TurnOffWindowsCopilot'; Exp=1 },
    @{ Cat='HKLM'; Check='Disable AI Data Analysis'; Path='HKLM:\SOFTWARE\Policies\Microsoft\Windows\WindowsAI'; Name='DisableAIDataAnalysis'; Exp=1 },
    @{ Cat='HKLM'; Check='Fast Startup Disabled'; Path='HKLM:\SYSTEM\CurrentControlSet\Control\Session Manager\Power'; Name='HiberbootEnabled'; Exp=0 },
    @{ Cat='HKLM'; Check='Disable Consumer Features'; Path='HKLM:\SOFTWARE\Policies\Microsoft\Windows\CloudContent'; Name='DisableWindowsConsumerFeatures'; Exp=1 },
    @{ Cat='HKLM'; Check='Telemetry Level 0'; Path='HKLM:\SOFTWARE\Policies\Microsoft\Windows\DataCollection'; Name='AllowTelemetry'; Exp=0 },
    @{ Cat='HKLM'; Check='CPU Priority (Background)'; Path='HKLM:\SYSTEM\CurrentControlSet\Control\PriorityControl'; Name='Win32PrioritySeparation'; Exp=0x26 },
    @{ Cat='HKLM'; Check='Network Throttling Max'; Path='HKLM:\SOFTWARE\Microsoft\Windows NT\CurrentVersion\Multimedia\SystemProfile'; Name='NetworkThrottlingIndex'; Exp=0xFFFFFFFF },
    @{ Cat='HKLM'; Check='Defender Sample Submission'; Path='HKLM:\SOFTWARE\Policies\Microsoft\Windows Defender\Spynet'; Name='SubmitSamplesConsent'; Exp=2 },
    @{ Cat='HKCU'; Check='Show Hidden Files'; Path='HKCU:\Software\Microsoft\Windows\CurrentVersion\Explorer\Advanced'; Name='Hidden'; Exp=1 },
    @{ Cat='HKCU'; Check='Show File Extensions'; Path='HKCU:\Software\Microsoft\Windows\CurrentVersion\Explorer\Advanced'; Name='HideFileExt'; Exp=0 },
    @{ Cat='HKCU'; Check='Launch to This PC'; Path='HKCU:\Software\Microsoft\Windows\CurrentVersion\Explorer\Advanced'; Name='LaunchTo'; Exp=1 },
    @{ Cat='HKCU'; Check='Disable Advertising ID'; Path='HKCU:\Software\Microsoft\Windows\CurrentVersion\AdvertisingInfo'; Name='Enabled'; Exp=0 },
    @{ Cat='Service'; Check='SysMain Disabled'; Exp='Disabled' },
    @{ Cat='System'; Check='Hibernation Disabled'; Exp='Disabled' },
    @{ Cat='Network'; Check='TCP Auto-Tuning Normal'; Exp='normal' }
)
$pass = 0; $fail = 0
foreach ($c in $checks) {
    $status = switch ($c.Cat) {
        'Service' { $svc = Get-Service SysMain -EA SilentlyContinue; if ($svc.StartType -eq $c.Exp) { 'PASS' } else { "FAIL ($($svc.StartType))" } }
        'System'  { $out = powercfg /a 2>$null | Select-String 'hibernate' -Quiet; if (-not $out) { 'PASS' } else { 'FAIL (Enabled)' } }
        'Network' { $out = netsh int tcp show global 2>$null | Select-String 'normal'; if ($out) { 'PASS' } else { 'FAIL' } }
        default   { Test-RegValue $c.Path $c.Name $c.Exp }
    }
    if ($status -eq 'PASS') { $pass++ } else { $fail++ }
    $report.Add("[$($c.Cat)] $($c.Check) : $status") | Out-Null
}
$report.Add('') | Out-Null
$report.Add("Summary: $pass Passed | $fail Failed") | Out-Null
$report.Add('') | Out-Null
$report | Out-File "$env:USERPROFILE\Desktop\VerificationResult.txt" -Force -Encoding utf8
Add-Type -AssemblyName System.Windows.Forms
$msg = "Deployment Verification Complete`n`nPassed: $pass`nFailed: $fail`n`nFull report saved to Desktop\VerificationResult.txt"
[System.Windows.Forms.MessageBox]::Show($msg, 'Configuration Check', 'OK', 'Information') | Out-Null
